define i32 @test15e_zext(i8 %X) {
  %t1 = and i8 %X, -128
  %t2 = icmp ne i8 %t1, 0
  %t3 = select i1 %t2, i32 256, i32 0
  ret i32 %t3
}

define i16 @test15f_trunc(i32 %X) {
  %t1 = and i32 %X, 128
  %t2 = icmp ne i32 %t1, 0
  %t3 = select i1 %t2, i16 0, i16 256
  ret i16 %t3
}
